sql:
SELECT name, IFNULL(sl_distance, 0) AS distance_from_squad_leader
FROM squad_members
ORDER BY distance_from_squad_leader ASC;

SELECT COUNT(member_id) AS num_deaths
FROM status_updates
WHERE status = 'Dead' AND updated_by = 'Commander Smith';

external_knowledge:
- "Top 3" refers to the highest ranks based on the total number of casualty reports;
- "Reported more than once" means the total number of casualty reports is greater than 1;
- "Alive or wounded" refers to the current status of the squad members.

- The highest minimum rank is 'Sergeant';
- Performance ratings are ranked as 'Excellent' (1), 'Good' (2), and 'Average' (3);
- The most recent mission is identified by the highest `squad_mission_id` for each member.

sql:
SELECT name, role, status
FROM squad_members
ORDER BY name ASC;

SELECT unit, COUNT(member_id) AS total_squad_members
FROM squad_members
GROUP BY unit;

